module reg_8bit (
    input wire clk,
    input wire rst,
    input wire en,
    input wire [7:0] d,
    output reg [7:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q <= 8'b00000000;
        else if (en)
            q <= d;
    end

endmodule
